module RefModule(
    input wire CLK,
    input wire RST,
    input wire UP,
    output reg [2:0] Q
    );

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (RST)
        Q <= 3'b0;
    else if (UP)
        Q <= Q + 1;
    else
        Q <= Q - 1;
end

endmodule
